import express from 'express';
import cors from 'cors';

// Import Vercel-style handlers
import entityHandler from './entities/[entity].js';
import authHandler from './auth/[action].js';
import functionHandler from './functions/[name].js';
import integrationHandler from './integrations/[name].js';

const app = express();
const PORT = process.env.PORT || 3100;

// Middleware
app.use(cors());
app.use(express.json({ limit: '10mb' }));

// Health check
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Adapt Vercel handler format (req.query.param) to Express (req.params.param)
function adaptHandler(handler, paramName) {
  return (req, res) => {
    // Vercel uses req.query for dynamic route params, Express uses req.params
    req.query[paramName] = req.params[paramName];
    return handler(req, res);
  };
}

// API Routes
app.all('/api/entities/:entity', adaptHandler(entityHandler, 'entity'));
app.all('/api/auth/:action', adaptHandler(authHandler, 'action'));
app.all('/api/functions/:name', adaptHandler(functionHandler, 'name'));
app.all('/api/integrations/:name', adaptHandler(integrationHandler, 'name'));

// Static images (uploaded products)
app.use('/images', express.static('/home/gilles/artroyal-api/images'));

app.listen(PORT, '127.0.0.1', () => {
  console.log(`Art Royal API running on http://127.0.0.1:${PORT}`);
});

